'use client';

import { useCheckout } from '@/components/cart/hooks/useCheckout';
import type { DeliveryAddress, PaymentInfo } from '@/components/cart/hooks/useCheckout';
import { CheckoutSteps } from '@/components/cart/Checkout/CheckoutSteps';
import { CheckoutSummary } from '@/components/cart/Checkout/CheckoutSummary';
import { Step1_Delivery } from '@/components/cart/Checkout/Step1_Delivery';
import { Step2_Payment } from '@/components/cart/Checkout/Step2_Payment';
import { Step3_Review } from '@/components/cart/Checkout/Step3_Review';
import { AnimatePresence, motion } from 'framer-motion';

export function Checkout() {
    const {
        currentStep,
        nextStep,
        prevStep,
        goToStep,
        deliveryAddress,
        setDeliveryAddress,
        paymentInfo,
        setPaymentInfo,
    } = useCheckout();

    const handleAddressSubmit = (address: DeliveryAddress) => {
        setDeliveryAddress(address);
        nextStep();
    };

    const handlePaymentNext = (info: PaymentInfo) => {
        setPaymentInfo(info);
        nextStep();
    };

    return (
        <div className="bg-background min-h-screen transition-colors duration-300">
            <div className="max-w-6xl mx-auto px-6 py-12">
                <h1 className="font-serif text-3xl text-foreground mb-8 text-center" style={{ fontFamily: 'var(--font-playfair, serif)' }}>Ödeme İşlemi</h1>

                <CheckoutSteps currentStep={currentStep} />

                <div className="mt-12 grid grid-cols-1 lg:grid-cols-12 gap-10 items-start">
                    <div className="lg:col-span-8">
                        <AnimatePresence mode="wait">
                            {currentStep === 'delivery' && (
                                <motion.div
                                    key="delivery"
                                    initial={{ opacity: 0, x: -20 }}
                                    animate={{ opacity: 1, x: 0 }}
                                    exit={{ opacity: 0, x: 20 }}
                                    transition={{ duration: 0.4 }}
                                >
                                    <Step1_Delivery onNext={handleAddressSubmit} />
                                </motion.div>
                            )}

                            {currentStep === 'payment' && (
                                <motion.div
                                    key="payment"
                                    initial={{ opacity: 0, x: -20 }}
                                    animate={{ opacity: 1, x: 0 }}
                                    exit={{ opacity: 0, x: 20 }}
                                    transition={{ duration: 0.4 }}
                                >
                                    <Step2_Payment onNext={handlePaymentNext} onPrev={prevStep} />
                                </motion.div>
                            )}

                            {currentStep === 'review' && (
                                <motion.div
                                    key="review"
                                    initial={{ opacity: 0, x: -20 }}
                                    animate={{ opacity: 1, x: 0 }}
                                    exit={{ opacity: 0, x: 20 }}
                                    transition={{ duration: 0.4 }}
                                >
                                    <Step3_Review
                                        deliveryAddress={deliveryAddress}
                                        paymentInfo={paymentInfo}
                                        onPrev={prevStep}
                                        onPrevToDelivery={() => goToStep('delivery')}
                                    />
                                </motion.div>
                            )}
                        </AnimatePresence>
                    </div>

                    <div className="lg:col-span-4 sticky top-24">
                        <CheckoutSummary />
                    </div>
                </div>
            </div>
        </div>
    );
}
