import { useState, useCallback } from 'react';

export type CheckoutStep = 'delivery' | 'payment' | 'review';

export interface DeliveryAddress {
    firstName: string;
    lastName: string;
    phone: string;
    email: string;
    address: string;
    city: string;
    district: string;
    postalCode: string;
    saveAddress?: boolean;
}

export interface PaymentInfo {
    method: 'card' | 'bank' | 'cod';
    cardLastFour?: string;
    cardName?: string;
}

export function useCheckout() {
    const [currentStep, setCurrentStep] = useState<CheckoutStep>('delivery');
    const [deliveryAddress, setDeliveryAddress] = useState<DeliveryAddress | null>(null);
    const [paymentInfo, setPaymentInfo] = useState<PaymentInfo>({ method: 'card' });

    const goToStep = useCallback((step: CheckoutStep) => {
        setCurrentStep(step);
        window.scrollTo(0, 0);
    }, []);

    const nextStep = useCallback(() => {
        if (currentStep === 'delivery') goToStep('payment');
        else if (currentStep === 'payment') goToStep('review');
    }, [currentStep, goToStep]);

    const prevStep = useCallback(() => {
        if (currentStep === 'payment') goToStep('delivery');
        else if (currentStep === 'review') goToStep('payment');
    }, [currentStep, goToStep]);

    return {
        currentStep,
        goToStep,
        nextStep,
        prevStep,
        deliveryAddress,
        setDeliveryAddress,
        paymentInfo,
        setPaymentInfo,
    };
}
